meta.script:
/* ╔══════════════════════════════════════════════════════════╗
   ║  CONFIG — sadece bu bolumu guncelleyin                   ║
   ╚══════════════════════════════════════════════════════════╝ */

const BUILD_CDN  = "https://cdn.jsdelivr.net/gh/gulamen/c86c7@main/Build";
const DATA_PARTS = 6;   /* Survival car.data.br  45 MB  → 6 part */
const WASM_PARTS = 7;   /* Survival car.wasm.br  56.4MB → 7 part */

/* ╔══════════════════════════════════════════════════════════╗
   ║  BURADAN ASAGI DOKUNMAYIN                                ║
   ╚══════════════════════════════════════════════════════════╝ */

const overlay = document.getElementById('loading-overlay');
const barFill = document.getElementById('bar-fill');
const barPct  = document.getElementById('bar-pct');
const barInfo = document.getElementById('bar-info');
const canvas  = document.querySelector('#unity-canvas');

function setBar(p, info) {
    barFill.style.width = p + '%';
    barPct.textContent  = Math.round(p) + '%';
    if (info !== undefined) barInfo.textContent = info;
}

/* Mobil viewport meta */
if (/iPhone|iPad|iPod|Android/i.test(navigator.userAgent)) {
    var meta = document.createElement('meta');
    meta.name    = 'viewport';
    meta.content = 'width=device-width,height=device-height,initial-scale=1.0,user-scalable=no,shrink-to-fit=yes';
    document.head.appendChild(meta);
}

document.addEventListener('contextmenu', e => e.preventDefault());
function focusGame() { canvas.focus(); }
window.addEventListener('pointerdown', focusGame);
window.addEventListener('touchstart',  focusGame);

/* Part indirme + birlestirme */
async function fetchParts(baseName, partCount, label, barStart, barEnd) {
    const parts = [];
    for (let i = 0; i < partCount; i++) {
        setBar(barStart + (i / partCount) * (barEnd - barStart),
               `${label} (${i+1}/${partCount}) wait...`);
        const r = await fetch(`${BUILD_CDN}/${encodeURIComponent(baseName)}.part${i}`);
        if (!r.ok) throw new Error(`${baseName}.part${i}: HTTP ${r.status}`);
        parts.push(new Uint8Array(await r.arrayBuffer()));
    }
    setBar(barEnd, `${label} birleştiriliyor...`);
    const total  = parts.reduce((s, p) => s + p.length, 0);
    const merged = new Uint8Array(total);
    let off = 0;
    for (const p of parts) { merged.set(p, off); off += p.length; }
    return merged;
}

/* Blob URL'ye .br fragment → Unity bundled brotli devreye girer */
function brBlobUrl(uint8, filename) {
    const blob = new Blob([uint8], { type: 'application/octet-stream' });
    return URL.createObjectURL(blob) + '#' + encodeURIComponent(filename);
}

(async function () {
    try {
        setBar(0, 'Hazırlanıyor...');

        /* 1) data.br */
        const dataBytes = await fetchParts('Survival car.data.br', DATA_PARTS, 'Data', 0, 40);
        const dataUrl   = brBlobUrl(dataBytes, 'Survival car.data.br');
        setBar(40);

        /* 2) wasm.br */
        const wasmBytes = await fetchParts('Survival car.wasm.br', WASM_PARTS, 'WASM', 40, 75);
        const wasmUrl   = brBlobUrl(wasmBytes, 'Survival car.wasm.br');
        setBar(75, 'Oyun yükleniyor...');

        /* 3) Framework — orijinal, parcalanmadi */
        const frameworkUrl = `${BUILD_CDN}/Survivalcar.framework.js`;

        /* 4) Config */
        const config = {
            dataUrl:            dataUrl,
            frameworkUrl:       frameworkUrl,
            codeUrl:            wasmUrl,
            streamingAssetsUrl: 'StreamingAssets',
            companyName:        'DefaultCompany',
            productName:        'Survival Car Race',
            productVersion:     '0.0.01',
            showBanner: (msg, type) => console[type === 'error' ? 'error' : 'warn'](msg),
        };

        /* 5) Loader — orijinal, parcalanmadi */
        await new Promise((res, rej) => {
            const s   = document.createElement('script');
            s.src     = `${BUILD_CDN}/Survivalcar.loader.js`;
            s.onload  = res;
            s.onerror = () => rej(new Error('Loader yüklenemedi'));
            document.body.appendChild(s);
        });
        setBar(80);

        /* 6) Unity */
        const inst = await createUnityInstance(canvas, config, (p) => {
            setBar(80 + Math.round(p * 20), '');
        });

        window.unityInstance = inst;
        setBar(100, '');
        overlay.style.display = 'none';
        focusGame();

    } catch (err) {
        console.error(err);
        setBar(0, '⚠ Hata: ' + err.message);
    }
})();
